def token_f1(a, b):
    # tokens by spaces
    ta = normalize_ar(a).split()
    tb = normalize_ar(b).split()
    if not ta or not tb:
        return 0.0
    ca = len(ta)
    cb = len(tb)
    common = 0
    tb_counts = {}
    for t in tb:
        tb_counts[t] = tb_counts.get(t, 0) + 1
    for t in ta:
        if tb_counts.get(t, 0) > 0:
            common += 1
            tb_counts[t] -= 1
    prec = common / ca
    rec = common / cb
    if prec + rec == 0:
        f1 = 0.0
    else:
        f1 = 2*prec*rec/(prec+rec)
    return f1, prec, rec, common, ca, cb

